def formula(Temp):
    import numpy as np
    A  = 1e+11
    Ea = 80000
    return A * np.exp(-Ea / (8.314 * Temp))

def formula(A_minus, HA):
    # Henderson-Hasselbalch equation with pKa = 6.5
    # A_minus: concentration of conjugate base [A-]
    # HA: concentration of weak acid [HA]
    return 6.5 + np.log10(A_minus / HA)

def formula(Sub):
    import numpy as np
    Vmax = 50
    Km   = 10
    return Vmax * Sub / (Km + Sub)

def formula(M):
    import numpy as np
    a = 3.5
    b = 0.75
    return a * np.power(np.abs(M), b)

def formula(a, b):
    # Pythagorean theorem: hypotenuse from two legs
    return np.sqrt(a**2 + b**2)

def formula(P, r, n, t):
    # P: principal amount
    # r: annual interest rate (decimal)
    # n: compounding frequency per year
    # t: time in years
    return P * (1 + r / n) ** (n * t)

def formula(A, K, L):
    # Cobb-Douglas production function
    # A = total factor productivity
    # K = capital input
    # L = labor input
    return A * np.power(K, 0.3) * np.power(L, 0.7)
